import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.xml.soap.*;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;

@WebService
public class XmlProcessingService {

    @WebMethod
    public String processXml(String soapMessage) {
        try {
            // Parse SOAP message
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage message = messageFactory.createMessage(new MimeHeaders(), new ByteArrayInputStream(soapMessage.getBytes()));
            SOAPBody body = message.getSOAPBody();

            // Parse XML content from the SOAP body
            DocumentBuilderFactory dbFactory = DocumentBuilderFactory.newInstance();
            DocumentBuilder dBuilder = dbFactory.newDocumentBuilder();
            Document doc = dBuilder.parse(new ByteArrayInputStream(body.getTextContent().getBytes()));

            // Handle complex XML structures
            NodeList nestedEntities = doc.getElementsByTagName("NestedEntity");
            for (int i = 0; i < nestedEntities.getLength(); i++) {
                String entityData = nestedEntities.item(i).getTextContent();
                // Process each nested entity as needed
                System.out.println("Processing Nested Entity: " + entityData);
            }

            return "XML processed successfully";
        } catch (Exception e) {
            e.printStackTrace();
            return "Error processing XML: " + e.getMessage();
        }
    }
}